(function () {
const grid = document.getElementById('home-gallery-grid');
if (!grid || typeof GALLERY_DATA === 'undefined') return;
const picks = [
{ src: '../images/trails/pct/361F5BDF-4AD3-4396-AFDC-4B3143AB1D00_1_105_c.jpeg',       label: 'Pacific Crest Trail' },
{ src: '../images/trails/at/01843EE0-9338-48A1-A28B-A13B7F3FE77D_1_105_c.jpeg',        label: 'Appalachian Trail' },
{ src: '../images/trails/tmb/DB2B2968-C0DF-4C55-8A2E-BE4935745324_1_105_c.jpeg',       label: 'Tour du Mont Blanc' },
{ src: '../images/trails/colorado/4795BA47-5262-4673-B2F4-A83E866AD8E9_1_105_c.jpeg',  label: 'Colorado Trail' },
{ src: '../images/trails/trt/089BAD7C-FB0C-4B68-9EB9-129FC8F4A470_1_105_c.jpeg',       label: 'Tahoe Rim Trail' },
{ src: '../images/trails/shasta/IMG_0051.JPG',                                          label: 'Mount Shasta' },
{ src: '../images/trails/whitney/IMG_6531.jpeg',                                        label: 'Mount Whitney' },
{ src: '../images/trails/lost-coast/06D9A56D-4446-490C-B74D-68E1795E200C_1_105_c.jpeg', label: 'Lost Coast Trail' },
{ src: '../images/trails/escalante/IMG_5393.jpeg',                                      label: 'Escalante Canyon Loop' },
];
picks.forEach(photo => {
const a = document.createElement('a');
a.href = 'pages/gallery.html';
a.className = 'home-gallery-item';
const img = document.createElement('img');
img.dataset.src = photo.src;
img.src = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 4 3"><rect fill="%23241e16" width="4" height="3"/></svg>';
img.alt = photo.label;
img.loading = 'lazy';
img.className = 'blur-up';
const overlay = document.createElement('div');
overlay.className = 'home-gallery-item-overlay';
overlay.innerHTML = `<span>${photo.label}</span>`;
a.appendChild(img);
a.appendChild(overlay);
grid.appendChild(a);
});
const obs = new IntersectionObserver(entries => {
entries.forEach(e => {
if (e.isIntersecting) {
const img = e.target;
if (img.dataset.src) {
const full = new Image();
full.onload = () => { img.src = img.dataset.src; delete img.dataset.src; img.classList.add('loaded'); };
full.src = img.dataset.src;
obs.unobserve(img);
}
}
});
}, { rootMargin: '300px' });
grid.querySelectorAll('img[data-src]').forEach(img => obs.observe(img));
})();